    @RustCleanup("Remove in V16.") // Not in libAnki
    fun findOneCardByNote(query: String, order: SortOrder = SortOrder.NoOrdering()): List<CardId> {
        // This function shouldn't exist and CardBrowser should be modified to use Notes,
        // so not much effort was expended here

        val noteIds = findNotes(query, order)
        if (noteIds.isEmpty()) {
            return emptyList()
        }
        // select the card with the lowest `ord` to show
        // The query result order matches the noteIds order from findNotes
        val noteIdToPosition = noteIds.withIndex().associate { it.value to it.index }
        // Get card id and note id pairs, then sort by note position to preserve order from findNotes
        return db.database.query(
            """
SELECT c.id, c.nid
FROM (
  SELECT nid, MIN(ord) AS ord
  FROM cards
  WHERE nid IN ${Utils.ids2str(noteIds)} 
  GROUP BY nid
) AS card_with_min_ord
JOIN cards AS c ON card_with_min_ord.nid = c.nid AND card_with_min_ord.ord = c.ord;
            """.trimMargin()
        ).use { cursor ->
            generateSequence { if (cursor.moveToNext()) cursor else null }
                .map { it.getLong(0) to it.getLong(1) } // (cardId, noteId)
                .sortedBy { noteIdToPosition[it.second] ?: Int.MAX_VALUE }
                .map { it.first }
                .toList()
        }
    }"}

