        fun fromCol(config: Config, preferences: SharedPreferences, cardsOrNotes: CardsOrNotes): SortType {
            val sortTypeKey = if (cardsOrNotes == CardsOrNotes.CARDS) "sortType" else "noteSortType"
            val colOrder = config.get<String>(sortTypeKey)
